import React from 'react'
import { Link } from 'gatsby'
import * as styles from './TopicCard.module.css'

const TopicCard = ({ slug, title, description, imageUrl, topicType, tagTitles = [] }) => {
  return (
    <Link to={`/library/${slug}`} className={styles.card}>
      <div className={styles.imageWrap}>
        {imageUrl ? (
          <img
            src={imageUrl}
            alt={title}
            className={styles.image}
            loading="lazy"
          />
        ) : (
          <div className={styles.imagePlaceholder}>📚</div>
        )}
      </div>
      <div className={styles.body}>
        {(tagTitles.length > 0 || topicType) && (
          <div className={styles.tags}>
            {tagTitles.map(tag => (
              <span key={tag} className={styles.tag}>{tag}</span>
            ))}
            {topicType && (
              <span className={styles.typeTag}>{topicType}</span>
            )}
          </div>
        )}
        <h3 className={styles.title}>{title}</h3>
        {description && (
          <p className={styles.description}>{description}</p>
        )}
      </div>
    </Link>
  )
}

export default TopicCard
